onClick:
{{
(() => {
  if (!SelectPowiat.selectedOptionValue) {
    showAlert("Wybierz powiat.", "warning");
    return;
  }

  if (!SelectGmina.selectedOptionValue) {
    showAlert("Wybierz gminę.", "warning");
    return;
  }

  if (!InputTytul.text.trim()) {
    showAlert("Podaj tytuł.", "warning");
    return;
  }

  insertDodajGPR.run(
    () => {
      getGPR.run(
        () => {
          closeModal("ModalDodajGPR");

          resetWidget("SelectPowiat", true);
          resetWidget("SelectGmina", true);
          resetWidget("InputTytul", true);
          resetWidget("DataZatwierdzenia", true);
          resetWidget("DataWpisu", true);
          resetWidget("InputLink", true);

          showAlert("Rekord został dodany.", "success");
        },
        (error) => {
          showAlert("Nie udało się odświeżyć tabeli: " + error.message, "warning");
        }
      );
    },
    (error) => {
      showAlert("Błąd zapisu: " + error.message, "error");
    }
  );
})();
}}
